  headers: Record<string, string>;
}

/** The JSON body sent to the webhook endpoint. */
export interface WebhookDelivery {
  url: string;
  method: 'POST';
  headers: Record<string, string>;
  body: WebhookBody;
  sentAt: Date;
  notificationId: string;
}

/** The structured JSON body of a webhook POST. */
export interface WebhookBody {
  notificationId: string;
  type: string;
  subject: string;
  body: string;
  recipient: string;
  createdAt: string;
  metadata?: Record<string, unknown>;
}

const URL_REGEX = /^https?:\/\/\S+/;

const DEFAULT_CONFIG: WebhookConfig = {
  maxRetries: 2,
  headers: {},
};

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private deliveries: WebhookDelivery[] = [];
  private config: WebhookConfig;
  /** Pluggable transport — override for testing or real HTTP clients. */
  private transport: (delivery: WebhookDelivery) => Promise<void>;

  constructor(config?: Partial<WebhookConfig>) {
    this.config = { ...DEFAULT_CONFIG, headers: { ...DEFAULT_CONFIG.headers, ...config?.headers }, ...config, headers: { ...DEFAULT_CONFIG.headers, ...config?.headers } };
    // Default transport: in-memory store (replace with fetch/axios/etc.)
    this.transport = async (delivery: WebhookDelivery) => {
      this.deliveries.push(delivery);
    };
  }

  /**
   * Replace the default in-memory transport with a custom one.
   * Use this to plug in a real HTTP client (fetch, axios, etc.).
   */
  setTransport(transport: (delivery: WebhookDelivery) => Promise<void>): void {
    this.transport = transport;
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const validationError = this.validateRecipient(payload.recipient);
    if (validationError) {
      this.logger.warn(`Invalid webhook URL "${payload.recipient}": ${validationError}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        deliveredAt: new Date(),
        error: validationError,
      };
    }

    const webhookBody = this.formatPayload(payload);

    const delivery: WebhookDelivery = {
      url: payload.recipient,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...this.config.headers,
      },
      body: webhookBody,
      sentAt: new Date(),
      notificationId: payload.id,
    };

    let lastError: string | undefined;
    for (let attempt = 0; attempt <= this.config.maxRetries; attempt++) {
      try {
        await this.transport(delivery);
        this.logger.info(
          `Webhook delivered to ${delivery.url} (attempt ${attempt + 1})`,
