      } catch (err) {
        lastError = err instanceof Error ? err.message : String(err);
        this.logger.warn(
          `Webhook attempt ${attempt + 1} failed for ${delivery.url}: ${lastError}`,
        );
      }
    }

    this.logger.error(
      `Webhook delivery failed after ${this.config.maxRetries + 1} attempts for ${delivery.url}`,
    );
    return {
      success: false,
      notificationId: payload.id,
      channel: this.channel,
      deliveredAt: new Date(),
      error: `Delivery failed after ${this.config.maxRetries + 1} attempts: ${lastError}`,
    };
  }

  /**
   * Validate that the recipient is a well-formed HTTP(S) URL.
   * Returns an error message if invalid, or undefined if valid.
   */
  validateRecipient(recipient: string): string | undefined {
    if (!recipient || recipient.trim().length === 0) {
      return 'Webhook URL is empty';
    }
    if (!URL_REGEX.test(recipient)) {
      return `Invalid webhook URL: ${recipient}`;
    }
    return undefined;
  }

  /**
   * Format a NotificationPayload into the JSON body sent to the webhook endpoint.
   */
